INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-23e15ae5-moex-00130', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「人一出生，其實就跟這個世界、跟他人之間有種『感通』的能量。如閱 讀文學時的感動，從《詩經》、《楚辭》到陶淵明、杜甫，能把別人的苦 痛變成自己生命的一部分。或是儒家思想所講的『惻隱』、『不忍』之心， 都是感通，這背後預設自我分享了別人的命運，他人就在個體的自我裡。 我們所要做的是讓這種能量變強，讓自己更能理解別人在想什麼。」 根據上文，下列選項何者正確？', '["感通力量人人皆備，只是文學家表達更為精準", "抒發情感貴在樸實真誠，才能更深入打動人心", "感通是自我能同理他人，將他人納入己身生命", "個體與群體之關係，可在傳統中找到所有答案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00131', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「可以鳳求凰或凰求鳯，可以叫賣價格低廉而美輪美奐的瓊樓玉宇，可以 報失，可以道歉，可以鳴謝救火，可以感謝良醫，可以宣揚仙丹，可以賀 人結婚，可以賀人家的兒子得博士學位，可以一大排一大排訃告同一某某 董事長的死訊，可以公開訴願喊冤，可以公開歌功頌德，可以宣告為某某 舉辦冥壽，可以公告拒絕往來戶，可以揭露各種考試的金榜，可以……不 勝枚舉。」 根據上文，可以有如此多功用的是指：', '["證書", "廣告", "新聞", "招牌"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00132', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「提出好問題對每個人來說都很重要。真正的好朋友會拿好問題來問你， 就像好父母一樣。從他們提出的問題，就可以知道他們對你的了解，還有 多麼關心你。他們提出的問題，會讓你停下來，好好思考，要你誠懇面對 自己，至於你是否真的能夠找到答案，倒不是那麼重要。提出讓人不禁思 考的好問題是一門藝術，我相信，也是一種值得好好培養的能力。」 根據上文，下列選項何者最符合文意？', '["好父母會像好朋友提出一樣的關鍵問題", "好的問題如同交友一樣，也是一門藝術", "從問題可了解提問者對我們的關注程度", "能夠誠懇地面對好問題，就能找到答案"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00133', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「我們常覺得是自己在做決定，但事實上在缺乏資訊時，會藉由觀察別人， 盡量蒐集片段的資料，然後加以模仿。模仿可以是個正當的策略，是一種 『社會學習』，透過和其他人的互動來學習，比自己獨力應付狀況時更聰 明些。不過模仿卻也經常把大家帶離正軌，因為模仿並不會產生任何新資 訊，只是擴大一些舊資訊可以帶來的效果，並且不管資訊是真是假。」 根據上文，下列選項最符合文意的是：', '["人們在絕大多數時間所下的決定，其實都並非出自自我判斷", "模仿其實也是不錯的學習方式，只要能在正當運用的範圍內", "社會學習意指由社會群體來做決定，以避免專斷獨裁的危險", "資訊充沛的時代，蒐集資料、觀察別人，是正確的學習策略"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00134', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「前不久，我返家，彷彿已經老去卻又元氣十足的奶奶，親暱地坐在我身 邊問我人生前途的種種課題，那些我答不出來也無意抵達的目標、方向、 可能。對話像飄搖的小舟行駛在晴日之海，懶洋洋。」 根據上文，下列選項最接近祖母和作者對話狀態的是：', '["作者有一搭沒一搭地被動回應祖母", "作者積極回應祖母，兩人聊得愉快", "祖母明知故問，作者只能羞愧沉默", "兩人互相試探，宛如小型的攻防戰"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00135', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '常言道：「這世界最可敬的事，就是比你聰明的人，卻比你還更加認真， 積極求上。」下列選項，最接近文意的是：', '["學如逆水行舟，不進則退", "一分天才，九十九分努力", "坐等機會，終將一事無成", "學海無涯，惟勤勞能補拙"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00136', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「坊間攝影書，最常提到的關鍵字不外乎是：景深、快門、光圈，種種競 選口號般速成式的激情，但我相信唯有勇氣、體貼與好奇，才能讓攝影與 生活產生更緊密的聯繫，我們似乎總是忘記，拍照最常用到的其實不是單 眼相機，是你的那雙眼睛。」 根據上文，下列選項何者最符合文意？', '["攝影書常為求速成而內容不實", "攝影要能等待時機、掌握變化", "具備審美的眼光就能拍出好照片", "養成攝影之眼需要細膩觀察生活"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00137', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「臺灣人許多時候將『飲食』視為社交活動，對食物很疏離，只對入口的 東西有慾望，但對食品產業結構、到身體產生什麼變化，不太關心，而且 過度追求『便宜大碗』的氛圍下，忽略食材、人工成本，廠商於是拚命壓 低成本，甚至走上偏路，消費者成了不健康競爭的間接推手。『不把態度 擺正，再多規範、溯源，都可以破解』，若要建立美食王國聲譽，臺灣消 費者可以做得更多。 」 根據上文，下列選項最符合文意的是：', '["食品法規無助於食品安全，消費者必須謹慎挑選", "廠商拚命壓低成本，以薄利多銷手法衝刺市占率", "消費者有健全的飲食態度，才能從源頭強化食安", "社會的停滯性通膨，導致消費者追求便宜又大碗"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00138', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「人在工作時，由於精神專注，意志集中，自能煥發出生命的光芒；在無 所事事時，人立即顯得無精打采，悵然若失，既看不到眼神中激昂的鬥志， 動作中的意氣風發也頹然若止。」 下列選項，最合乎本文意旨的是：', '["精神專注可提升工作效率", "人在專心工作時最具光彩", "工作讓人年輕且活得充實", "離開工作會讓人獲得自由"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL),
  ('disabled-23e15ae5-moex-00139', 'disabled-23e15ae5', 'disabled-23e15ae5-moex-112-34c7f7f6', 'sub-disabled-23e15ae5-01', NULL, 'single_choice', '「弓頭鯨的名稱得自巨大而獨特的弓狀頭顱。其軀體非常沉重，雖然至今 還未曾整個或局部地被秤過，一般相信就其體長來看，應該比其他的鯨都 重。經常與一角鯨、白鯨結伴，是生活在北極的唯一大型鯨類動物。鯨脂 厚達70公分，有助其禦寒；能穿破厚達30公分的冰層，為自己開鑿呼吸 孔。有顯著的白色下巴，身上沒有皮繭，也沒有背鰭，這些特徵應足以用 來辨認。」 根據上文，下列選項正確的是：', '["弓頭鯨之名來自其弓狀的頭顱，可能是世界上最長的鯨豚", "弓頭鯨、一角鯨、白鯨，都是棲息於北極的大型鯨類動物", "弓頭鯨擁有厚重的脂肪，主要功能在於抵禦棲地嚴酷的低溫", "弓頭鯨全身呈現黑色、藍黑色，但只有胸鰭和尾鰭是深褐色"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:47+00:00", "source_pdf_sha1": "5c2eaeb81861", "answer_pdf_sha1": "ad67f96c0b18", "source_family": "moex-gov-tw", "moex": {"exam_code": "112050", "c": "504", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文", "year": "112", "exam_name": "112年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "電腦打字"}'::jsonb, NULL)
